import type { SSHService } from '../SSHService';
import type { RegistryService } from '../RegistryService';
import type { NixpacksService } from '../NixpacksService';
import type { TraefikService } from '../TraefikService';
import type { ZeroDowntimeDeployer } from './ZeroDowntimeDeployer';
import type { LogEntry } from './types';

export type DockerStackServiceContext = {
  sshService: SSHService;
  registryService: RegistryService;
  nixpacksService: NixpacksService;
  traefikService: TraefikService;
  zeroDowntimeDeployer: ZeroDowntimeDeployer;
  emitLog: (message: string, type?: LogEntry['type'], stackId?: string, deploymentId?: string) => void;
  initDeploymentLogs: (deploymentId: string) => void;
  saveDeploymentLogs: (deploymentId: string) => void;
  uploadFile: (serverId: string, path: string, content: string) => Promise<void>;
  ensureDockerInstalled: (serverId: string) => Promise<void>;
  createEnvFile: (serverId: string, workingDir: string, envVars: Record<string, string>) => Promise<void>;
  ensureEnvFileDirective: (serverId: string, workingDir: string, stackId: string) => Promise<void>;
};
